using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiTool
{
    [McpServerTool(Name = "fetch_data"), Description("Fetches data from an external API endpoint.")]
    public static async Task<string> FetchDataAsync(
        IHttpClientFactory httpClientFactory,
        [Description("The API path to call (e.g. \"/users/1\").")] string path,
        CancellationToken cancellationToken)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        using var response = await client.GetAsync(path.TrimStart('/'), cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizationPrompt
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a summarization prompt for the given text.")]
    public static GetPromptResult Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum length hint (e.g. \"2 sentences\").")] string? maxLength = null)
    {
        var instruction = maxLength is not null
            ? $"Summarize the following text in at most {maxLength}."
            : "Summarize the following text concisely.";

        return new GetPromptResult
        {
            Description = "Summarization prompt",
            Messages =
            [
                new PromptMessage
                {
                    Role = Role.User,
                    Content = new TextContentBlock { Text = $"{instruction}\n\n{text}" },
                },
            ],
        };
    }
}

